import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [userRole, setUserRole] = useState('');
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', categoria: '', stock: 0, precio_compra: 0, precio_venta: 0, fecha_caducidad: '' });

  const cargarDatos = async () => {
    try {
      const resStats = await axios.get('http://localhost:5000/api/stats');
      setStats(resStats.data);
      const resProds = await axios.get('http://localhost:5000/api/productos');
      setProductos(resProds.data);
    } catch (e) { console.log("Error de conexión"); }
  };

  useEffect(() => { if (isLoggedIn) cargarDatos(); }, [isLoggedIn]);

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setIsLoggedIn(true);
        setUserRole(res.data.rol);
      }
    } catch (e) { alert("Usuario o contraseña incorrectos"); }
  };

  const guardarProducto = async () => {
    try {
      if (editMode) {
        await axios.put(`http://localhost:5000/api/productos/${selectedId}`, nuevoProd);
      } else {
        await axios.post('http://localhost:5000/api/productos', nuevoProd);
      }
      setShowForm(false); setEditMode(false); cargarDatos();
      alert("¡Guardado correctamente!");
    } catch (e) { alert("Error al guardar. Revisa los datos."); }
  };

  const prepararEdicion = (p) => {
    setSelectedId(p.id);
    setNuevoProd({ ...p, fecha_caducidad: p.fecha_caducidad ? p.fecha_caducidad.split('T')[0] : '' });
    setEditMode(true);
    setShowForm(true);
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Borrar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- 1. VISTA LOGIN (RESTAURADA AL DISEÑO ORIGINAL) ---
  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>Iniciar Sesión</h2>
          <div className="form-group">
            <label>Usuario:</label>
            <input type="text" placeholder="eduardo" value={usuario} onChange={(e) => setUsuario(e.target.value)} />
          </div>
          <div className="form-group">
            <label>Contraseña:</label>
            <input type="password" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
          </div>
          <button className="btn-entrar" onClick={handleLogin}>Entrar</button>
          <button className="btn-registrar">Registrarse</button>
        </div>
      </div>
    );
  }

  // --- 2. VISTA DASHBOARD / GESTIÓN ---
  return (
    <div>
      <header className="header">
        <h1>Mi Tiendita - {view === 'dashboard' ? 'Dashboard' : 'Inventario'}</h1>
        <button className="btn-cerrar" onClick={() => setIsLoggedIn(false)}>Cerrar Sesión</button>
      </header>
      <nav className="nav-bar">
        <span className="nav-link" onClick={() => setView('dashboard')}>Inicio / Dashboard</span>
        {userRole === 'admin' && <span className="nav-link" onClick={() => setView('gestion')}>Gestionar Productos</span>}
      </nav>

      <main style={{ padding: '20px' }}>
        {view === 'dashboard' ? (
          <div className="dashboard-grid">
            <div className="card clickable" onClick={() => setView('gestion')}>
                <h3>Productos con Bajo Stock</h3>
                <div className="card-content">{stats.bajo_stock} productos agotándose.</div>
            </div>
            <div className="card">
                <h3>Estadísticas Rápidas</h3>
                <div className="card-content">
                    <p>Total Productos: {stats.total_productos}</p>
                    <p>Valor Total: ${stats.valor_inventario}</p>
                </div>
            </div>
          </div>
        ) : (
          <div className="card">
            <button className="btn-entrar" style={{width:'auto', marginBottom:'20px'}} onClick={() => { setShowForm(!showForm); setEditMode(false); }}>
                {showForm ? 'Cancelar' : '+ Agregar Producto'}
            </button>

            {showForm && (
              <div style={{background:'#f4f4f4', padding:'15px', borderRadius:'8px', marginBottom:'20px'}}>
                <input type="text" placeholder="Nombre" value={nuevoProd.nombre} onChange={e=>setNuevoProd({...nuevoProd, nombre:e.target.value})} />
                <input type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e=>setNuevoProd({...nuevoProd, stock:e.target.value})} />
                <input type="number" placeholder="Precio Venta" value={nuevoProd.precio_venta} onChange={e=>setNuevoProd({...nuevoProd, precio_venta:e.target.value})} />
                <button className="btn-entrar" onClick={guardarProducto}>{editMode ? 'Actualizar' : 'Guardar'}</button>
              </div>
            )}

            <table style={{width:'100%', textAlign:'left'}}>
              <thead>
                <tr><th>Producto</th><th>Stock</th><th>Precio</th><th>Acciones</th></tr>
              </thead>
              <tbody>
                {productos.map(p => (
                  <tr key={p.id} className="table-row">
                    <td>{p.nombre}</td>
                    <td>{p.stock}</td>
                    <td>${p.precio_venta}</td>
                    <td>
                      <button onClick={() => prepararEdicion(p)}>✏️</button>
                      <button onClick={() => eliminar(p.id)}>🗑️</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
